INSERT INTO sub_areas (id, attraction_id, name_en, name_zh, body, cover_image_path, sort_order, is_active)
VALUES
  ('chengdu_panda_base_sa_01', 'chengdu_panda_base', 'Adult, Sub-Adult and Juvenile Giant Panda Villas', '成年亚成年幼年大熊猫别墅', 'Located in the central core area of the base, this villa complex is composed of multiple independent courtyards linked together. Each courtyard includes an indoor enclosure, an outdoor activity field, perches, and a pool. The villas house pandas by age—adults over 2 years, sub-adults 1-2 years, and juveniles 6 months-1 year—with each panda having its own indoor room and shared outdoor area. Through glass walls, visitors can closely observe daily behaviors such as eating bamboo, climbing trees, sleeping, and playing in water. It is one of the areas where most visitors linger longest and take the most photos. In winter (November to next March), some pandas may be moved indoors—please refer to on-site announcements.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_panda_base_sa_01.jpg', 0),
  ('chengdu_panda_base_sa_02', 'chengdu_panda_base', 'Giant Panda Museum', '大熊猫博物馆', 'Adjacent to the South Gate entrance, the Giant Panda Museum is the first indoor stop after entering the park. The two-story museum covers about 4,000 square meters and features permanent exhibitions including "Panda Origins," "Panda Evolution," "Panda Ecology," "Panda Conservation," and "World Panda Distribution." Through fossil specimens, skeletal models, taxidermy specimens, HD videos, and interactive installations, it systematically tells the 8-million-year evolutionary story of giant pandas. The museum houses a 4D cinema (looping "Panda Mission," about 15 minutes per session)—the most popular stop for families with children and educational groups.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_panda_base_sa_02.jpg', 1),
  ('chengdu_panda_base_sa_03', 'chengdu_panda_base', 'Giant Panda Sun Delivery Room', '大熊猫太阳产房', 'Located in the central area of the base, adjacent to the Moon Nursery, the Sun Nursery is one of the earliest cub-rearing facilities built at the base in the 1980s. The nursery is a closed, constant-temperature building divided into multiple independent cub-rearing rooms, each accommodating one mother panda and 1-2 newborn cubs. During the cub-rearing season (approximately June to November), mother pandas spend the first few months with their newborn cubs in the nursery. Through the glass observation windows, visitors can see the pink newborn cubs gradually grow their "black eye patches." In the off-season, it is transformed into a giant panda science exhibition hall, introducing knowledge about cub-rearing, breeding research, and growth cycles.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_panda_base_sa_03.jpg', 2),
  ('chengdu_panda_base_sa_04', 'chengdu_panda_base', 'Giant Panda Star Delivery Room', '大熊猫星星产房', 'Located at the northernmost end of the base''s new area, adjacent to the New Area Exhibition Hall and the Panda Tower, the Star Nursery is a high-end cub-rearing facility newly opened in 2024. The nursery''s exterior features a "starry sky" theme design (deep blue facade + LED starry ceiling), with internal divisions by constellation: Big Dipper Zone, Aries Zone, Scorpio Zone, etc., each corresponding to a set of cub-rearing rooms + supporting observation windows. The nursery uses a fully enclosed constant temperature and humidity system + 24-hour AI behavior monitoring + real-time live broadcast (growth videos of newborn pandas can be watched via the base''s official WeChat account during certain periods). This nursery mainly undertakes the dual tasks of "high-end cub-rearing demonstration" and "scientific breeding" at the base. **Note**: Due to cub-rearing needs, it may not be open to the public during certain periods—please refer to on-site announcements.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_panda_base_sa_04.jpg', 3),
  ('chengdu_panda_base_sa_05', 'chengdu_panda_base', 'Giant Panda Moon Delivery Room', '大熊猫月亮产房', 'Located in the central core area of the base, facing the Sun Nursery across a path, the Moon Nursery is a modern cub-rearing facility expanded by the base in the 2010s. The building has a half-spherical exterior (mimicking the lunar phase) and is internally divided by "lunar phases": the Full Moon Hall serves cub-rearing families, the First Quarter Hall is a science exhibition hall, and the Last Quarter Hall is a research monitoring room. During the cub-rearing season (approximately June to November), mother pandas live here with their newborn cubs. Through the floor-to-ceiling glass, visitors can clearly see the heartwarming scenes of panda mothers holding, nursing, and grooming their cubs—making it one of the base''s "Internet celebrity check-in spots." In the off-season, the Moon Hall is transformed into a 4D cinema or themed temporary exhibition area.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_panda_base_sa_05.jpg', 4),
  ('chengdu_panda_base_sa_06', 'chengdu_panda_base', 'South Gate', '南大门', 'Located at the southernmost end of the base facing Xiongmao Avenue, the South Gate is the base''s iconic gateway. It features a bionic design—columns mimicking the panda''s "black eye patches," a golden plaque reading "Chengdu Research Base of Giant Panda Breeding" on the lintel, and panda silhouettes with bamboo reliefs. The spacious plaza in front houses a visitor center, luggage storage, wheelchair/stroller rental, and audio guide rental. The right side has group lanes and accessible lanes. After security, visitors scan their reservation QR code or use face recognition to enter—making it the base''s busiest and most photogenic gate.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_panda_base_sa_06.jpg', 5),
  ('chengdu_panda_base_sa_07', 'chengdu_panda_base', 'West Gate', '西门', 'Located at the westernmost end of the base, adjacent to the entrance of the "Moon" Pavilion Group and the western slope of Moon Mountain, the West Gate is the base''s secondary entrance (the South Gate is the main entrance). The West Gate uses a "panda" bionic design language consistent with the South Gate, but with a smaller scale and simpler style, mainly serving visitors arriving by car or bus from the west of Chenghua District/Xindu District. Inside the gate is a small visitor center (inquiries, wheelchair rental, guide map pickup), and outside the gate is a parking lot (about 200 spaces) and a bus stop (Bus 198, 655 to "Panda Base West Gate" stop). The West Gate is open year-round and is the designated entrance for the "Moon" Pavilion Group night session ("Bright Moon" light show 19:00-21:00).', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_panda_base_sa_07.jpg', 6),
  ('chengdu_panda_base_sa_08', 'chengdu_panda_base', 'West Zone "Yue" (Moon) Pavilion Group', '西区"月"字展馆群', 'The West Zone "Yue" (Moon) Pavilion Group is a core visiting area recently expanded by the Chengdu Panda Base, consisting of multiple ecological pavilions named with the character "Yue" (Moon), including Daiyue Pavilion, Lanyue Pavilion, and Wangyue Pavilion. These cleverly echo the profound connection between the moon and natural imagery in traditional Chinese culture. The pavilions are built following the terrain, utilizing extensive transparent designs and natural lighting to seamlessly connect indoor and outdoor spaces, creating a poetic environment of dancing bamboo shadows and murmuring streams. Each pavilion displays giant pandas of different age groups and social units. As visitors stroll through, they can observe pandas eating, climbing, and resting in various behavioral states. The pavilion group also incorporates rich science displays, with interactive knowledge walls and electronic touchscreens along the visiting route, introducing giant panda habitat conservation, bamboo diet, and social behavior. The entire area is connected by walking paths, ideal for slow, in-depth exploration, and represents the essence of the base''s ecological civilization achievements.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_panda_base_sa_08.jpg', 7),
  ('chengdu_panda_base_sa_09', 'chengdu_panda_base', 'Red Panda No.1 & No.2 Activity Yards', '小熊猫1号2号活动场', 'Located on the east and west sides of the Moon Mountain trail in the central base, Red Panda Activity Fields No.1 and No.2 are the base''s earliest publicly opened outdoor red panda activity areas. Each field has independent fences and simulates the red panda''s native high-mountain forest—dense forest, flowing water, perches, deadwood holes, and rain shelter cabins. The two fields are connected by a walking boardwalk, allowing visitors to observe natural behaviors such as napping on branches, leaping, and curling tails to shade the sun. The area is spacious with open views. **Note the distinction from the "Red Panda Moon Nursery"**: the Moon Nursery tends toward breeding (semi-enclosed), while No.1/No.2 activity fields are open outdoor activity areas.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_panda_base_sa_09.jpg', 8),
  ('chengdu_panda_base_sa_10', 'chengdu_panda_base', 'Red Panda Moon Delivery Room', '小熊猫月亮产房', 'Located in the Moon Mountain area of the base, the Red Panda Moon Nursery is designed for breeding red pandas (scientific name: Ailurus fulgens, also known as "lesser panda" or "red bear-cat"). The "Moon Nursery" name comes from its proximity to the Moon Nursery area and the shared moon-phase-inspired architectural design—it does not house baby giant pandas. The area is divided into multiple semi-wild activity zones by lunar phase, each simulating the red panda''s native high-mountain forest environment, equipped with perches, deadwood, flowing water, and small wooden houses. Through glass walls and wooden fences, visitors can observe behaviors such as tree-climbing, leaping, tail-curling, and feeding. This area is one of the favorite "cute check-in spots" for families with children.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_panda_base_sa_10.jpg', 9),
  ('chengdu_panda_base_sa_11', 'chengdu_panda_base', 'New Area Exhibition Halls', '新区展馆', 'Located at the core of the base''s new area (northern expansion zone), adjacent to the New Area Panda Villa and the entrance to the Panda Tower, the New Area Exhibition Hall is a comprehensive hall newly built in the 2020s. The hall is divided into two floors: the first floor is the giant panda-themed science exhibition hall (fossils, skeletons, habitat panoramas, breeding research results), and the second floor houses the "Panda VR Immersive Experience Hall," "Panda Theme Post Office," and "Panda Cultural & Creative Retail." The hall exit leads directly to the Panda Tower and the new area observation deck. Outside the hall is the New Area Central Plaza, which hosts panda-themed pop-ups and seasonal science activities year-round—making it a complex node for "science + cultural creativity + experience" at the base.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_panda_base_sa_11.jpg', 10),
  ('chengdu_panda_base_sa_12', 'chengdu_panda_base', 'Panda Art Museum', '熊猫美术馆', 'Located on the east side of the New Area Central Plaza in the base, adjacent to the New Area Exhibition Hall, the Panda Art Museum is a small art museum newly built in the 2020s. The museum covers about 800 square meters, divided into two floors: the first floor is the permanent exhibition hall (displaying panda-themed paintings, sculptures, and photography works by domestic and foreign artists, about 80-120 pieces), and the second floor is the temporary exhibition hall (3-4 themed exhibitions per year, having hosted "Pandas and Children''s Paintings," "Panda Image Chronicles," "International Panda Art Biennale," etc.). The museum''s design is simple and bright, with floor-to-ceiling glass walls that let natural light become the best exhibition filter. The museum houses a cultural creative shop selling limited edition art derivatives (postcards, prints, silk scarves, T-shirts, etc.).', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_panda_base_sa_12.jpg', 11),
  ('chengdu_panda_base_sa_13', 'chengdu_panda_base', 'Panda Tower', '熊猫塔', 'Located on the north side of the New Area Central Plaza of the base, the Panda Tower is a new observation/science landmark built in the 2020s. The tower is about 30 meters tall (some sources say about 50 meters, please refer to the on-site nameplate), with an exterior shaped like a giant "panda head + bamboo leaves"—the facade features black, white, and green spliced into a "panda" outline. The tower has elevators and walking stairs; the top floor is a 360° observation deck that overlooks the entire base new area (northern expansion zone) with its villas, activity fields, nurseries, and Moon Mountain. The first floor of the tower is the "Panda Tower · Themed Coffee Area," the second floor is the "Panda Photography Gallery," and the third floor is the observation deck. There is an LED light show on the tower at night (19:00-21:00). **Note**: Information about the actual height of the Panda Tower varies between 30 meters and 50 meters—please refer to the on-site nameplate.', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_panda_base_sa_13.jpg', 12),
  ('chengdu_panda_base_sa_14', 'chengdu_panda_base', 'Panda Post Office', '熊猫邮局', 'Located on the north side of the first floor of the New Area Exhibition Hall at the base, the Panda Post Office is a "Panda-themed Postal Cultural Creativity Experience Point" cooperating with China Post—it is not a traditional post office. The store mainly sells panda-themed postcards, commemorative stamp albums, commemorative seals, local stationery stickers, commemorative envelopes, and other cultural creative products. Visitors can stamp the exclusive "Panda Post Office" commemorative seal on site and mail to any country in the world (additional postage required). This "themed post office" model is common in tourist attractions both in China and abroad, functioning more like a "panda-themed cultural creativity store" + "commemorative seal experience point"—for services such as registered mail, courier, or cash withdrawal, please visit the nearest post office on Xiongmao Avenue in Chenghua District outside the base (about 1.5 km).', 'https://edwvrriuwzaaqznklrgi.supabase.co/storage/v1/object/public/cover-images/sub-areas/all/chengdu_panda_base_sa_14.jpg', 13)
